    ['Breaking the Ice'] = {
        id = 54,
        start_npc = 'Traiffeaux',
        start_zone = 'Kamihr Drifts',
        start_pos = 'K-10',
        description = 'Walls of sheer ice are impeding colonization in Kamihr Drifts. You need to find the weak spot in these walls--but your ears will freeze without a pair of earmuffs. Collect three rabbit hides and one raaz tusk and bring them to Traiffeaux.',
        reward = '"Fragmenting" Pair of fuzzy earmuffs and 500 Bayld',
