    ['Children of the Rune'] = {
        id = 119,
        start_npc = 'Octavien',
        start_zone = 'Eastern Adoulin',
        start_pos = 'I-8',
        description = 'Years of excruciating training and long hours of study await those who desire to master the runic arts. One may circumvent this laborious process, however, by engraving runes upon his body with ink from a Yahse wildflower petal.',
        reward = 'Sowilo Claymore\nAbility to become a Rune Fencer.',
        fame = 'Adoulin',
        fame_level = '1',
        title = 'Runic Engraver',
        repeatable = nil,
        previous = nil,
        next = {
            'Endeavoring to Awaken',
            'Rune Fencing the Night Away',
        },
        requirements = nil,
        walkthrough = '1. Speak with Octavien at (I-8), accessed via the stairs.\n2. Obtain a Yahse wildflower petal from Yahse Hunting Grounds at (K-7) by examining the Yahse Wildflower.\n   - The Yahse Wildflower is found on the northern of the three beaches.\n3. Speak with Octavien again and attempt to "Use Rune Enhancement."\n   - The amount of attempts required can be from anywhere between 1 and 100, but it does not appear that you can fail.\n     - Every 10th failure, he will remark on your progress:\n     - 10th fail: "I sense an ominous force interfering with your progress... Could it be the  within you?!"\n     - 20th fail: "Your 20th attempt and we\'re still no closer than before? Perhaps \'tis I who needs to train more, so I don\'t accidentally give the talentless dreams they can never accomplish."\n     - 30th fail: "I was under the impression that you were an adventurer renowned throughout the Middle Lands. Apparently that appellation amounts to little more than kindling for the fires of one\'s boasting."\n     - 40th fail: "...My condolences, sir/madame."\n     - 50th fail: "Why don\'t you quit while you still have your health? Many people would commit atrocities for a body as hale and hearty as yours."\n     - 60th fail: "Let me say this one thing: you may think you\'re special, but you\'re just as special as everyone else...that is to say, not at all."\n     - 70th fail: "I lost hope for you long ago, but this is already your 70th time. Any further attempts would be a waste of time for us both."\n     - 80th fail: "Zzz..."\n     - 90th fail: "I\'ve had enough of your incompetence! Let me spell this out loud and clear: y-o-u c-a-n-n-o-t u-s-e r-u-n-e-s!"\n     - 99th fail: "I might as well stick around to see if you can make it an even 100."\n4. When you succeed, you will be rewarded with access to the Rune Fencer job and a Sowilo Claymore!',
        notes = nil,
    },
    ['Dances with Luopans'] = {
        id = 118,
        start_npc = 'Sylvie',
        start_zone = 'Western Adoulin',
        start_pos = 'I-5',
        description = 'The intricacies of a geomancer lie in the luopans--compatriots in the casting of advanced magics. To make one, you need one petrified log and a fistful of homeland soil. Now where could you find them...?',
        reward = 'Indi-Poison (Scroll)\nMatre Bell\nAbility to become a Geomancer',
        fame = 'Adoulin',
        fame_level = '1',
        title = 'Geodancer',
        repeatable = nil,
        previous = nil,
        next = {'Elementary, My Dear Sylvie'},
        requirements = nil,
        walkthrough = '1. Speak to Sylvie at Western Adoulin Waterfront (I-5) Waypoint #9.\n2. Venture to the crag closest to your home nation and click the Ergon Locus ??? located beneath the stairs leading up to the Telepoint to obtain a [Key Item] Fistful of homeland soil.\n   - San d\'Oria - La Theine Plateau (K-8)\n   - Bastok - Konschtat Highlands\n   - Windurst - Tahrongi Canyon (I-6)\n3. Return to Sylvie with the soil and trade her a Petrified Log to receive the [Key Item] Luopan.\n4. Proceed to one of following Ergon Locus:\n   - Flourishing Island - Ceizak Battlegrounds (K-10, Frontier Station)\n   - Bud of the Swarm - Ceizak Battlegrounds (I-8, Bivouac #2)\n   - Immutable Boulder - Yahse Hunting Grounds (F-6, Bivouac #2)\n5. Upon arriving at one of the locations above, you will receive a message stating that "You are assaulted by an uncanny sensation."\n   - Use the rest (/heal) command to begin charging your [Key Item] Luopan.\n6. It can take up to 8 minutes of resting to gain enough of the lifestream to warm your [Key Item] Luopan.\n   - Once you have gathered enough energy, you will receive a message saying "You feel a mystical warmth welling up inside you!"\n7. After receiving this message, return to Sylvie to complete the quest.\n:WARNING: Each time you toss the Handbell reward from this quest then talk to Sylvie for AF and Empyrean Quests, she will ask for 300k gil or 150k bayld. Don\'t toss it until you finish Treasures of the Earth for Empyrean Body.\n      - Speaking to her again may allow you to skip paying.',
        notes = nil,
    },
    ['Destiny\'s Device'] = {
        id = 25,
        start_npc = 'Octavien',
        start_zone = 'Eastern Adoulin',
        start_pos = 'I-8',
        description = 'Unearth the truth behind the ultimate trial so the Order of Orvail can avoid any more tragedies such as the one that took place two years prior.',
        reward = 'Runeist Coat',
        fame = 'Seekers of Adoulin',
        fame_level = nil,
        title = 'Ultimate Runeist',
        repeatable = nil,
        previous = {'Legacies Lost and Found'},
        next = {
            'Rune Fencer Relic Armor',
            'Quiescence',
        },
        requirements = nil,
        walkthrough = '1. Speak to Octavien at Eastern Adoulin (I-8) while on Rune Fencer, He will give you the Key Item Runic kinegraver.\n2. Speak to Gaddiux at the Inventors\' Coalition (Western Adoulin (J-10)), selecting the option referencing Adoulinian Kelp.\n   - Next, Pick the top 2 options. (Ask if the rune stone is still there) and (The trial objectives.) until he mention the  Yahse wildflower petal.\n3. Click the Yahse Wildflower in Yahse Hunting Grounds at (K-7) to receive a Yahse wildflower petal.\n4. In Marjami Ravine, travel to the ??? at the base of the waterfall east of Bivouac #2 at (I-8). Use Ignis three times, and then interact with the ??? for a cutscene and a [Key Item] Vial of vivid rainbow extract.\n   - If you get stuck and don\'t get the cutscene return to Gaddiux and repeat the above until he tells you to first get a Yahse Wildflower petal and then head to Marjami.\n5. Speak to Gaddiux once more, again selecting the option referencing Adoulinian Kelp, for another cutscene.\n6. Speak to Octavien.\n7. Travel to the secret beach at (J-11) in Foret de Hennetiel (south of Bivouac #2) and examine the Bloodstained Glove on the shoreline for a cutscene.\n8. After all party members have watched the cutscene, click the Bloodstained Glove once more to spawn Insidio. This cutscene and fight can be done as any job, and Trusts are usable.\n   - Insidio is an Orobon NM which notably has access to Mayhem Lantern (AoE Charm).\n     - Upon each usage of Mayhem Lantern, Insidio will gain a significant reduction to physical damage taken until it takes nearly no physical damage.\n   - Party members actively participating in the quest will receive a Insidio\'s extinguished lantern upon defeat. Other members who are assisting will receive up to 10,000 Bayld (depending on the size of the party), if they have never assisted in this battle before.\n   - Strategy for Insidio - If attempting to solo this fight, the easiest way to do so is to summon your trusts, preferably those that can deal magic damage, your best dps, and those that can Skillchain.  Now pop Insidio and let your trusts get hate.  Once they\'ve gained a decent amount of hate, move well out of range of charm AoE. Alternatively use Tenebrae with Pflug and other Magic Evasion buffs. Now sit back and watch your trusts do all the work.  Using this strategy with ilvl 119 gear trusts easily took down NM within 8-10 minutes.\n9. (Optional) Examine the Bloodstained Glove after defeating Insidio.\n10. Return to Octavien to complete the quest and receive your reward.\n11. (Optional) Talk to Zurko-Bazurko in Mhaura at the proto-waypoint for additional cutscene.  He will ask you to give him the runic kinegraver.',
        notes = nil,
    },
    ['Did You Feel That?'] = {
        id = 62,
        start_npc = 'Udip Ferawoh',
        start_zone = 'Marjami Ravine',
        start_pos = nil,
        description = 'Velkk have been planting spinescent protuberances all throughout the ravine, and Udip Ferawoh is sick of it. She wants you to suffer five amnesic attacks from them before returning--but don\'t get in over your head.',
        reward = '[Key Item]Restrainment resilience\n500 bayld',
        fame = 'Adoulin',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Talk to Udip Ferawoh at the Marjami Ravine Frontier Station\n2. Get amnesia 5 times from Spinescent Protuberance\n   - Apparently only the Marjami Ravine ones work.\n   - Some may be found around (H-10) (go through the tunnel with the Riverscum).\n   - Alternatively take Bivouac #1 and there is one at (L-12).\n   - Shell or magic evasion gear may reduce your chances of being afflicted.\n3. The message "You feel you have learned all you can from the spinescent protruberances. Report back to Udip Ferawoh with your findings." will display when you have been afflicted 5 times.\n   - This is a very finicky quest.  If this message does not display, then 1 or more of the amnesia attacks did not count for one reason or another, and you will need to be hit by amnesia some more.  See discussion page for more info.\n     - With only a Bullwhip Belt on and no gear/weapons, the amnesia effect is nearly guaranteed to land. Just be careful of the surrounding Velkks, they hit hard when you\'re naked especially with the belt on.\n4. Return to Udip Ferawoh to complete the quest and receive 500 bayld and the Restrainment resilience key item.',
        notes = nil,
    },
