    ['Do Not Go Into the Light'] = {
        id = 122,
        start_npc = 'Alianne',
        start_zone = 'Western Adoulin',
        start_pos = 'I-8',
        description = 'The young man who benefitted from the Hennebloom leaves you gave to Svenja would like to thank you in person. Go to the infirmary and hear what he has to say.',
        reward = '1,000 Bayld',
        fame = 'Adoulin',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'Flowers for Svenja'},
        next = {'Hypocritical Oath'},
        requirements = nil,
        walkthrough = '1. You must wait a game day after completing Flowers for Svenja before you may flag this quest.\n2. Click on the door to Svenja\'s Manor at (I-8) in Western Adoulin (Closest to the Courier\'s Coalition Waypoint).\n3. Next click on the door (despite being told it\'s "to the left," when you exit the cutscene, it\'s on your right, going towards the bridge) to the Hospital at (I-9) in Western Adoulin.\n4. Speak to Borghest at the Morimar Basalt Fields Frontier Station.\n5. Obtain a piece of Urunday Lumber, a Damascus Ingot, and a Fire Crystal.\n6. Trade the items to Chanteillie at the Inventors\' Coalition to receive the Inventors\' Coalition pickaxe key item.\n   - Chanteillie will not take the items if she is waiting for the items for quest Vegetable Vegetable Crisis.\n7. Head back to the Hospital to complete the quest.',
