    ['Don\'t Clam Up on Me Now'] = {
        id = 5,
        start_npc = 'Oblor',
        start_zone = 'Yahse Hunting Grounds',
        start_pos = 'K-9',
        description = 'Rations are starting to run low, and it\'s up to you to find some more! Collect five shellfish found along the seashore in Yahse Hunting Grounds.',
        reward = '1000 Experience Points\n100 Bayld',
        fame = 'Adoulin',
        fame_level = '1',
        title = 'None',
        repeatable = 'No',
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak to Oblor (K-9) at the Frontier Station.\n2. Collect five Shellfish from one of the beaches on the east side of the map.\n   - (K-7) has a beach with Orobons. Examining a Shellfish in this location has a chance of spawning an Alluring Orobon.\n   - (K-8) has a beach with Uragnites. Examining a Shellfish in this location has a chance of spawning a Startled Uragnite.\n     - The NMs that pop appear to have no unique drops, but only spawn to delay your gathering. You do not have to kill them, and you will not always spawn one. Both NMs are sleepable.\n     - Note that you cannot zone during or after collecting the required shellfish as they will all be lost.\n     - Locations are semi-random and the same clam can\'t be collected twice, either by the same player or by two different players. A replacement will immediately spawn on the same beach when one is interacted with.\n3. Return to Oblor for your reward to complete the quest.',
        notes = nil,
    },
    ['Don\'t Ever Leaf Me'] = {
        id = 70,
        start_npc = 'Audibert',
        start_zone = 'Eastern Adoulin',
        start_pos = 'F-9',
        description = 'The leafkin are mysterious yet adorable creatures, and one of their biggest fans wants to learn more about them. Assist him in unearthing information about their habitats and life cycles.',
        reward = '1200 Bayld',
        fame = 'Adoulin',
        fame_level = '1',
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = {
            {name = 'Fishing rod and lure', count = 1},
        },
        walkthrough = '1. Speak with Audibert in the Scouts\' Coalition.\n2. Complete the following 3 tasks to complete the quest.\n   - You do not have to return to Audibert each time you complete one of the mini-quests. You may speak with him after all are finished, though you will need to interact with him three times.\n# Speak to Corpo-Vorpo in the Peacekeepers\' Coalition. Travel Southeast from the Frontier Station in Morimar Basalt Fields and Examine the Daunting Emanation at (K-10) between 20:00-4:00 for a cutscene.\nReturn to Audibert for 400 bayld.\n# Speak to Barenngo in the Pioneers\' Coalition. Travel North from Bivouac #1 in Yahse Hunting Grounds, take your first right then follow the left wall.\nExamine the Windblown Loam at (J-6) for a cutscene.\nReturn to Audibert for 100 bayld.\n# Speak to Dewalt in the Couriers\' Coalition.\nFish up a Rusted pickaxe in Foret de Hennetiel.\nNote: The quest Flavors of Our Lives blocks progress to acquire the Rusted pickaxe, be sure Flavors of Our Lives is not active or you will not be able to fish up the [Key Item] Rusted pickaxe.\nReturn to Audibert for 700 bayld.\n3. Fishing right beside the Homepoint with any good fishing rod and any bait works well. A cheap rod may break. Carbon Fishing Rod, Halcyon Rod, Lu Shang\'s Fishing Rod etc. will work.\n4. Insect Ball seemed to be an effective bait to use, aside from sometimes being able to fish up an arrowwood log when the same message below.\n5. Rusted pickaxe gives the same fishing message that items normally give but is a bit harder to reel in.\n      - With max fishing skill, the Rusted pickaxe is very quick to fish up, like any other item without any noticeable difficulty.\n6. With low fishing skill, the Rusted pickaxe will sometimes give the Monster Reel-In Music instead of normal fishing reel-in music.\n7. Messages include:\n   - "You feel something pulling at your line."\n   - "You have a good feeling about this one!"\n   - " obtains a Rusted pickaxe!"\nNotes:\n8. The [Key Item]Rusted pickaxe counts as a fished-up "rusted" item, and has been tested to qualify for objectives such as Reel In Multiple Rusted Objects from RoE and Master Angler (VBD) from Vana\'Bout.\n9. Unlike the partial Bayld awards, this quest doesn\'t provide any fame for each part until you finish all three – it silently rewards you with that you only at the very end.\n::(determined with testing & attentiveness to Iyvah Halohm\'s dialogs on alts)',
        notes = nil,
    },
