    ['For Whom the Bell Tolls'] = {
        id = 36,
        start_npc = 'Sylvie',
        start_zone = 'Western Adoulin',
        start_pos = 'I-5',
        description = 'Sylvie\'s father, the venerable Hostenn, has gone missing, and Sylvie seeks the assistance of Ikhi Askamot. Head to the Order of Renaye Residence to beseech her aid.',
        reward = 'Filiae Bell \nDowser\'s Wand \n4,000-10,000 Bayld',
