        fame_level = nil,
        title = nil,
        repeatable = 'No',
        previous = {'Elementary, My Dear Sylvie'},
        next = {'The Bloodline of Zacariah'},
        requirements = {
            {name = '[Key Item] Silver luopan', count = 1},
        },
        walkthrough = '1. Speak to Sylvie at Western Adoulin Waterfront (I-5) Waypoint #9 to begin the quest.\n   - Geomancer must be set as your main job to activate the quest. The quest can be done on any job.\n2. Speak to Nhili Uvolep at Eastern Adoulin (I-7), Sverdhried Hillock Waypoint #7, for a cutscene.\n   - If you still have the Trial Wand or get the WS trial wand from her, talk to her again until you get the correct cutscene with Sylvie, zoning is not necessary.\n3. Travel to (K-10) Morimar Basalt Fields Frontier Station and speak to Vestavius.\n4. Travel to (J-6) Morimar Basalt Fields (at the north-west corner of (J-6) which is accessible by traveling east from Bivouac #2) and examine the "Ergon Locus ???" (south of the giant rock, not sparkling) for a cutscene and to obtain Silver luopan Key Item.\n   - Those not in possession of the Silver luopan Key Item will receive a one-time Bayld reward; size of the reward depends on the number of players present for the defeat of the NM.\n5. Examine the Ergon Locus ??? a second time to spawn Deranged Ameretat.\n   - Has approximately 75k HP.\n   - The NM primarily uses Sweet Breath and Bad Breath. It is also capable of using Extremely Bad Breath (less than 50%HP), but the cast time is long enough to run out of range.\n   - The NM will not use Extremely Bad Breath as long as an enfeebling Indi- or Geo- effect is active.\n   - The NM has very high Magic Evasion and magic damage reduction and is immune to nearly all enfeebles including Stun.\n   - It is recommended to use ranged trusts; ie Apururu, Semih Lafihna, Tenzen II, Makki-Chebukki, etc.\n6. Upon defeating the Deranged Ameretat, examine the Ergon Locus ??? a third time for a cutscene.\n   - You will lose the Silver luopan Key Item.\n7. Return to Sylvie (I-5) Western Adoulin for the final cutscene and your rewards.\n8. You must wait a game day before beginning the next quest.',
        notes = nil,
    },
    ['Forging New Bonds'] = {
        id = 23,
        start_npc = 'Octavien',
        start_zone = 'Eastern Adoulin',
        start_pos = 'I-8',
        description = 'Scour the lands for a capable blacksmith who can fashion a sword worthy of displaying at the Order of Orvail\'s traditional ceremony.',
        reward = 'Beorc Sword \nAbility to commission Runeist Armor crafting at Tomato Vantage Point',
        fame = 'Seekers of Adoulin',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'Endeavoring to Awaken'},
        next = {'Legacies Lost and Found'},
        requirements = nil,
        walkthrough = '1. Zone and come back to speak with Octavien after finishing the last quest. He is in Eastern Adoulin at (I-8) near the Sverdhried Hillock waypoint.\n   - You no longer need to be a Rune Fencer after this point.\n2. (Optional) Speak with Gaddiux at Inventors\' Coalition in Western Adoulin (J-10) on the blacksmith\'s whereabouts.\n3. Check the Inconspicuous Barrel in Western Adoulin (I-4), in the alley near the Adoulin Waterfront waypoint. Yestin-Ovestin appears on the wall during a cutscene, and asks for a Rune saber and a Frost-encrusted flame gem.\n4. (Optional) Return to Octavien for additional dialogue.\n5. Check the Tomato Vantage Point in the Arboretum in Rala Waterways (E-10) (closest access is from the entrance near Western Adoulin\'s Mog house) for a cutscene with Jerra Ndala.\n   - Ask her about the Rune saber. You\'ll need to trade either a Sowilo Claymore or an Elixir to the Tomato Vantage Point to get the Key Item Rune saber.\n   - Ask for the Frost-encrusted flame gem, and she\'ll give you a Flask of fruiserum Key Item.\n6. Go to Moh Gates and trade an Ifritite to the Molten Rift at (K-8) for a cutscene, where you will lose the Flask of fruiserum.\n   - Morimar Frontier Station waypoint is the fastest way to Moh Gates.\n     - If you don\'t have that waypoint unlocked, another fast route is from Yahse Bivouac #1.\n   - You must go through a Colonization Reive @ I-7.\n   - If you are doing multiple, make sure everyone trades their Ifritite to the Molten Rift before spawning the NM.\n7. Check the Molten Rift again to spawn the NM Staumarth.\n   - Fight is Soloable by a 118 RUN/DNC using Trusts.  See the Talk page for Information.\n     - It takes a very long time to kill this as RUN because it resists every form of damage except Thunder and it spams Spectral Floe or Scouring Spate (up to 30 seconds Terror or removes on piece of gear) Recommended to have gear sets made.\n     - Note: If you are defeated, you do not need another Ifritite to summon the NM again. Simply interact with the Molten Rift again to make it reappear.\n   - You do not need to be a Rune Fencer for the fight.\n   - The surrounding Apex Efts are non-aggressive.\n   - Upon defeating it, you will get the Frost-encrusted flame gem Key Item.\n8. Check the Inconspicuous Barrel in Western Adoulin (I-4) for a cutscene, where you will lose the Rune saber and Frost-encrusted flame gem key items.\n9. Check the Inconspicuous Barrel after one game day has passed. There will be a note instructing you to talk to Octavien.\n10. Talk with Octavien to receive the Beorc Sword.\n11. Note:  Completing this quest allows the player to commission the three non-quested pieces of Rune Fencer artifact armor from the Tomato Vantage Point at (E-10) Rala Waterways. Western Adoulin Mog House is closest entrance.',
        notes = nil,
    },
