    ['Order Up'] = {
        id = 30,
        start_npc = 'Reja Ygridhi',
        start_zone = 'Eastern Adoulin',
        start_pos = nil,
        description = 'Visit the Twelve Orders and ascertain whether or not the information contained within the dossier that the library prepared on them is correct.',
        reward = '1000 Experience Points\n500 Bayld\nAbility to read the books in Celennia Memorial Library\nAbility to receive achievement rewards from Reja Ygridhi',
        fame = 'Adoulin',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Obtain Celennia Memorial Library card from Patient Snake in the Scouts\' Coalition - Eastern Adoulin (F-9).\n2. Speak with  Reja Ygridhi inside the Celennia Memorial Library.\n3. After a brief conversation and accepting the quest, you are given the [Key Item] Twelve Orders dossier.\n4. Visit the following people for each of the Twelve Orders:\n   - Order of Haverton: Jozhud, followed by Palomel at (G-9) in Eastern Adoulin.\n     - If Palomel says "Oh, Maester Svenja, how I yearn to be swept up in your toned-yet-lithe arms and lose myself in your deep, calming gaze..." rather than the library related comment, you may need to complete A Thirst for the Ages first if it\'s currently flagged but incomplete. ( Source)\n     - If you are on A Thirst for the Eons, and she only gives you the dialog for that quest, you can skip over Palomel and still finish this quest.\n   - Order of Vocane: Oscairn at (G-7) in Eastern Adoulin.\n   - Order of Renaye: Nhili Uvolep at (I-7) in Eastern Adoulin.\n   - Order of Weatherspoon: Rigobertine at (J-7) in Eastern Adoulin, at the very top.\n     - If she starts a cutscene, speak again until she talks about documents.\n   - Order of Gorney: Oingo-Zoingo at (K-9) in Eastern Adoulin.\n   - Order of Adoulin: Ploh Trishbahk at (K-9) in Eastern Adoulin, at the main gate.\n     - If Ploh Trishbahk says "Thank you for proferring your dinner invitation..." rather than the library related comment, you may need to complete the mission Meeting of the Minds if it\'s currently flagged but incomplete.\n   - Order of Woltaris: Chumli-Mojumli at (K-10) in Eastern Adoulin. (That\'s all for the Eastern half of the city.)\n   - Order of Orvail: Terwok at (K-10) in Western Adoulin.\n   - Order of Thurandaut: Marjoirelle at (H-12) in Western Adoulin.\n   - Order of Janniston: Grevan at (I-8) in Western Adoulin.\n   - Order of Shneddick: Mastan at (G-6) in Western Adoulin.\n   - Order of Karieyh: Oka Qhantari at (D-8) in Western Adoulin.\n5. Return to Reja Ygridhi inside the Celennia Memorial Library for your reward.',
        notes = nil,
    },
    ['Orobon Appetit'] = {
