    ['Quiescence'] = {
        id = 132,
        start_npc = 'Gaddiux',
        start_zone = 'Western Adoulin',
        start_pos = nil,
        description = '[This is a challenge] You smell of rotten-wotten rolanberries. Now come fightaru me.',
        reward = 'Epeolatry',
        fame = 'Adoulin',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'Destiny\'s Device'},
        next = nil,
        requirements = nil,
        walkthrough = 'This quest has several parts and is rather time-consuming.\n1. Speak with Gaddiux at the Inventors\' Coalition.\n      - Note:If you are working towards an Idris, you will need to complete or quit that weapon to begin working on Epeolatry. You will lose all materials deposited if you quit, but you will keep your Rusted handbell key item and can restart it immediately.\n         - However, after completing any part after completing part 1, before trading your Lexeme Blade to Runje Desaali to begin the next part, any part of Saved by the Bell may be started and finished without having to restart either quest from the beginning.\n2. Obtain a Pickaxe, you will only need one.\n      - This may be easily purchased from Tevigogo in Western Adoulin at (D-9) near the Pioneers Coalition.\n      - Trailblazing Pickaxe also works.\n3. Head to (I-8) in Yorcia Weald and examine the ???.\n      - From Bivouac #2 head north past the Colonization Reive and then east into the field of numbing blossoms.\n         - There is more than one ??? in this location. If nothing happens, look around for the other ???.\n      - There is a bush that may be blocking the path at (H-8). It opens from 21:00 to 03:00 game time.\n4. When your "Enlightened Endeavor" key item resonates, trade the Pickaxe to the ???.\n      - You will obtain a Numbing blossom seed key item.\n      - Your "Enlightened Endeavor" will resonate that something is hidden further down in the earth, continue digging until you obtain Broken rapier hilt key item.\n      - If you are too slow you don\'t get the Key Item but can try again right away.\n5. Return to Gaddiux at the Inventors\' Coalition.\n6. Speak with Runje Desaali at (J-11) in Eastern Adoulin. She will begin tracking materials deposited towards Epeolatry.',
        notes = nil,
    },
    ['Raptor Rapture'] = {
        id = 73,
        start_npc = 'Pagnelle',
        start_zone = 'Western Adoulin',
        start_pos = 'G-10',
        description = 'Vorahal, the Mummers\' Coalition\'s most prized raptor, escaped his pen and evidently mauled a hapless citizen named Ilney. Go visit the victim and hear his side of the story.',
        reward = '1000 Bayld',
        fame = 'Adoulin',
        fame_level = '1',
        title = nil,
        repeatable = 'No',
        previous = nil,
        next = {'Vegetable Vegetable Crisis'},
        requirements = nil,
        walkthrough = '1. Speak with Pagnelle (G-10) in Western Adoulin near Mummers Coalition for a cutscene.\n2. Speak with Gontrain (H-12, next to the residential area) for a cutscene.\n3. Return to Pagnelle for another cutscene.\n4. Travel to the Ceizak Battlegrounds and obtain three rockberries by harvesting at a Harvesting Point. The berries are key items and are obtained at random, so bring multiple Sickles. Rockberries will be obtained with priority over normal items, so all rockberries may be obtained at one harvesting point; however, you will still be subject to gathering fatigue. (Sickle pretty much breaks on every harvest.)\n   - Known harvesting point locations:\n     - Intersection of three paths at E/F-8 boundary\n     - Intersection of three paths at G/H-8 boundary\n     - Far southeast corner of the map\n     - Southwest corner at (E-10)\n     - Bivouac #3 at (F-9)\n     - Northwest corner at (F-6)\n5. Return to Pagnelle for another cutscene.\n6. Travel to the Rala Waterways (enter from J-12 in Western Adoulin) and go to (E-11) near where Relentless Storm and Jaroney-Baroney stand on a bridge and close to a door. A cutscene will trigger automatically.\n7. Return to Pagnelle to complete the quest.',
        notes = nil,
    },
