        requirements = {
            {name = '[Key Item] Lhaiso Neftereh\'s bell', count = 1},
        },
        walkthrough = '1. Speak to Sylvie at Western Adoulin Waterfront (I-5) Waypoint #9 to begin the quest.\n   - Geomancer must be set as your main job to activate the quest. Can be completed as any job.\n2. WARNING: The following two Windower addons will crash your game if you attempt this quest while running them:\n   - "FastCS" causes this cutscene to freeze. Unload the addon (//lua u fastcs) before speaking to Nhili Uvolep if you use it. Also make sure you\'re at 30 fps (//config FrameRateDivisor 2) - froze Apr \'23 because of this.\n3. Speak to Nhili Uvolep at Eastern Adoulin (I-7), Sverdhried Hillock Waypoint #7, for another cutscene and to receive the Lhaiso Neftereh\'s bell Key Item.\n   - If you still have the Trial Wand or receive the quest Geomancerrific instead from Nhili Uvolep, talk to her twice to trigger the right cutscene.\n   - Those not in possession of Lhaiso Neftereh\'s bell Key Item will receive a Bayld reward. The size of the reward depends on the number of players present for assisting with defeating the Ancestral Rage. You can only receive this reward once.\n4. Travel to M-8/9 in Cirdas Caverns and examine the Overgrown Grave for a cutscene.\n   - Cirdas Caverns - Augural Conveyor is the fastest warp, otherwise Yorcia Weald Frontier Station.\n   - A Colonization Reive may block the way and will need to be cleared to reach the grave.\n5. Examine the Overgrown Grave again to spawn an Ancestral Rage NM.\n   - Has approximately 70k HP.\n   - This NM is a Gravitation elemental (earth and darkness) with very high physical damage reduction.\n   - Uses high level Earth and Darkness magic including Sleepga 2, AOE Drain, and AOE Aspir.\n   - Can use Entomb (AOE Earth damage, Slow, Petrify, and Hate Reset) and Tenebral Crush (AOE Darkness damage, Defense Down).\n   - Monk job ability Formless Strikes does not work on this NM.\n   - Can be slept with Repose and Lullaby.\n6. Upon defeating the Ancestral Rage, examine the Overgrown Grave again for a cutscene.\n7. Return to Sylvie for one last cutscene, your reward, and title. You will also lose Lhaiso Neftereh\'s bell.',
        notes = nil,
    },
    ['The Curious Case of Melvien'] = {
        id = 138,
        start_npc = 'Estelle',
        start_zone = 'Eastern Adoulin',
        start_pos = 'F-9',
        description = 'Margret postulated that Melvien\'s death was by human hands. Aid her in finding the truth.',
        reward = '4k Experience Points, 1,250 Bayld\n5 Pinches of High-Purity Bayld',
        fame = 'Adoulin',
        fame_level = '7',
        title = nil,
        repeatable = nil,
        previous = nil,
        next = {'A Thirst Before Time'},
        requirements = nil,
        walkthrough = '1. Talk to Estelle (F-9) in Eastern Adoulin behind the Scout Coalition building. You will receive Margret\'s writ of summons.\n2. Check the ??? in the crates in the alcove next to the base of the ramp at (I-9) for a cutscene. You will receive Portrait of Melvien\n   - The quest will appear in your quest log at this point.\n3. Talk to Chumli-Mojumli (K-10) and ask for Estienneux.\n   - The Castle Adoulin gates waypoint is closest.\n   - Select "Tell me about Melvien when he was alive" followed by "Show him the portrait of Melvien." You will receive Melvien\'s turn.\n4. Talk to Mastan (G-6) in Western Adoulin.\n   - The Platea Triumphus waypoint is closest. Go north and then make a left before the ramp down.\n   - Select "Tell me about Soufrriand\'s death." followed by "Show him the portrait of Melvien. Then select "I believe you.". You will receive Melvien\'s death?.\n5. Return to the crate at Eastern Adoulin (I-9) for a cutscene. You will receive Margret\'s memo.\n6. Go to Rala Waterways (H-6) and check the Storage Container for a cutscene.\n   - The nearest entrance is at Western Adoulin (Big Bridge K-8).\n7. You have to answer 2 questions right in the cutscene to continue, the answers are:\n#Arciela.\n#Morimar.\n8. Return to the crate at Eastern Adoulin (I-9) for a cutscene.\n   - Select "Show your Ring of supernal disjunction".\n9. Talk to Estelle (F-9) for your reward.',
        notes = nil,
    },
