    ['The Weatherspoon Inquisition'] = {
        id = 136,
        start_npc = 'Nashu',
        start_zone = 'Eastern Adoulin',
        start_pos = nil,
        description = 'Under the orders of Vortimere, Araustoix has led a contingent of exorcists on a witch hunt of the most literal kind. Head to Yorcia Weald with Nashu to warn the enigmatic Blackthorn Coven.',
        reward = '500 EXP\n1,000 Bayld',
        fame = 'Seekers of Adoulin',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'The Good, the Bad, the Clement'},
        next = {'The Weatherspoon War'},
        requirements = nil,
        walkthrough = '1. Zone into Western Adoulin from Ceizak Battlegrounds for a cutscene.\n2. Check the Occultist Footprints at the west side of (J-6) in Yorcia Weald, north from the Frontier Station to receive [Key Item] Sturdy hide pouch.\n3. Visit the following Ergon Locus in any order:\n   - Sih Gates: Lake of Light at (K-7)\n     - Take the Ceizak Battlegrounds bivouac #3 and head south.\n     - Take the Ceizak Battlegrounds bivouac #1 instead, and head south if you want to avoid one Reive in Sih Gates.\n   - Moh Gates: Sweltering Spring at (K-6/7)\n     - Take the Morimar Basalt Fields Frontier Station and head south east.\n   - Dho Gates: Saliferous Spring at (F/G-12)\n     - The Foret de Hennetiel waypoint #4 is suggested.\n     - Head south west and zone in at E-10.\n4. Zone into Cirdas Caverns for a cutscene.\n   - Zoning in using the Enigmatic Device warp works.\n     - Proceed south east from there.\n5. Check the Hiding Place at the southeast corner of (K-7) for a cutscene and your reward.',
        notes = nil,
    },
    ['The Weatherspoon War'] = {
        id = 141,
        start_npc = 'Nashu',
        start_zone = 'Marjami Ravine',
        start_pos = nil,
        description = 'The Velkk, Mligni-Vorgut, has seized an artifact with the power to destroy Adoulin. The exorcists want you to help stop him at the Seat of Gramk-Droog.',
        reward = '1,000 Experience Points\n1,000 Bayld',
        fame = 'Adoulin',
        fame_level = nil,
        title = 'Protector of the Sacred City',
        repeatable = nil,
        previous = {'The Weatherspoon Inquisition'},
        next = nil,
        requirements = nil,
        walkthrough = '1. Talk to Zaffeld at (J-8) in Eastern Adoulin.\n2. Zone into Marjami Ravine from Dho Gates for a cutscene. The quest will then appear in your log.\n   - The easiest way to do this is to warp to the Frontier Station. Zone in to Dho Gates to the north, then zone back into Marjami Ravine.\n3. Warp from the Frontier Station to Bivouac #2, then head southeast.\n   - When you come to a small watch tower, enter the tunnel there at J-9/10. Then continue to (I-10).\n     - Climb up the vine when you reach the tent/reive.\n4. Examine the Seat of Gramk-Droog at (I-10) for a cutscene.\n5. Examine it again to spawn Mligni-Vorgut.\n   - This monster is a Black Mage, see their page for more information.\n6. After the battle, examine the seat one last time for a cutscene.\n7. Return to the city and go to Western Adoulin to check the Hospital at (I-9) (Across from Flapano) for a cutscene.\n8. Return to Zaffeld at (J-8) in Eastern Adoulin for the final cutscene and reward.',
        notes = 'Due to translation errors, in the final scene Ilney is named Cilmad, and an Elvaan man\'s name changes from Adrastien to Ilney.\nAlso, if you happen to discard your Barkarole Earring you can speak with Zaffeld again to recover it for 10,000 Bayld.',
    },
    ['The Whole Place Is Abuzz'] = {
