        start_npc = 'Rumin-Flumin',
        start_zone = 'Yahse Hunting Grounds',
        start_pos = 'H-9',
        description = 'Numbing blossoms have antidotal effects that inhibit the poisons of pungent fungi. Head to the dead end to the southwest and use the Land of Milk and Honey beehive to collect ten bees. Make sure you are resting quietly to collect them!',
        reward = '[Key Item]Toxin resilience\n500 Bayld',
        fame = 'Adoulin',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Talk to Rumin-Flumin (H-9) Bivouac #3 in Yahse Hunting Grounds to obtain the Land of Milk and Honey hive.\n2. Run southwest a bit to the Pollinating Swarm at (G-10)\n3. Click on the Pollinating Swarm and then /heal until it counts 10 bees caught, then stand up.\n4. Click on the Pollinating Swarm again to receive the key item Full Land of Milk and Honey hive.\n   - (Optional) Go back to Rumin-Flumin and speak to him again\n5. Finally talk to Ndah Tolohjin (North) outside the Scouts\' Coalition (Eastern Adoulin #2) to receive your reward.',
        notes = nil,
