        start_zone = 'Eastern Adoulin',
        start_pos = 'J-8',
        description = 'The Blackthorn Coven has been causing inordinate amounts of trouble for Adoulin with the traps they are setting. Trek to J-6 in Yorcia Weald to capture these mavens of mischief and set the sacred city at ease.',
        reward = '1,000 Bayld',
