        start_npc = 'Lucretia',
        start_zone = 'Ceizak Battlegrounds',
        start_pos = 'H-9',
        description = 'One of the local mantids has been terrorizing the area. Use some of the chapuli around the bivouac as bait to lure it out of hiding and exterminate the threat.',
