        title = nil,
        repeatable = nil,
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Talk to Lucretia the guard at Bivouac #1 in Ceizak Battlegrounds and begin the quest.\n2. Kill Fernfelling Chapulis (directly to the south of the start NPC, at H-9) until you obtain the Mantid bait key item.\n3. Use it to spawn Truculent Mantis at the Claw Mark, directly to the north of the start NPC at H-8.\n   - Defeating this NM will reward Flayed mantid corpse.\n4. Return to Lucretia and exchange the Flayed mantid corpse for your reward.',
