    ['To Laugh Is to Love'] = {
        id = 104,
        start_npc = 'Peladi Shalmohr',
        start_zone = 'Western Adoulin Mummers\' Coalition',
        start_pos = 'G-10',
        description = 'Tuffle-Buffle requests your input to help Musto-Rusto win over his love, Minnifi.',
        reward = '1000 Experience Points',
        fame = 'Adoulin',
        fame_level = '3',
        title = 'The Lovelorn',
        repeatable = nil,
        previous = {'All the Way to the Bank'},
        next = {'A Barrel of Laughs'},
        requirements = nil,
        walkthrough = '1. You need to wait until the day changes after completing the previous quest.\n2. Talk to Peladi Shalmohr at the Mummers\' Coalition in Western Adoulin to begin the quest.\n3. Travel to (J-11) and click on the Mischief Marker for a cutscene.\n   - You will be asked to choose one of three hats for Musto-Rusto to wear, one of three pick up lines to use, one of three poses to perform, and a myriad of food to give the Mithra. All to attract the Mithra\'s affection.\n     - The Qiqirn Hood, Great Cook, Lively Jig and Senroh Skewer combination will always result in success, according to numerous sources (see Talk Page).\n4. Obtain the food you selected for the gift.\n   - Malgrom in Eastern Adoulin (E-8) sells Senroh Skewer for approx. 7,000 gil.\n5. Trade the food to the Mischief Marker for a cutscene (and quest completion if you chose a winning combination).',
        notes = nil,
    },
