        start_npc = 'Sylvie',
        start_zone = 'Western Adoulin',
        start_pos = 'I-5',
        description = 'Sylvie still has lingering doubts about her father. Meet up with her in Morimar Basalt Fields for moral support.',
        reward = 'Azimuth Coat \n15,000 Experience Points\n10,000 Bayld (109 Fight) or\n3 Synthesis Materials (125 Fight) or\n10 Synthesis Mats and a Codex of Etchings (135 Fight)',
        fame = 'Adoulin',
        fame_level = nil,
        title = 'Lifecycler (Level 135 fight only)',
        repeatable = 'Yes',
        previous = {'Geomancer Relic Armor'},
        next = nil,
        requirements = {
