    ['Vegetable Vegetable Crisis'] = {
        id = 110,
        start_npc = 'Amchuchu (Inventors\' Coalition',
        start_zone = 'Western Adoulin)',
        start_pos = nil,
        description = 'Amchuchu asks you deliver a missive\n to Cid proclaiming that Junior\'s plan\n fell through--but first, she wants you\n to bring back a midrium ingot, some\n urunday lumber, and a square of\n raaz leather.',
        reward = '12 Rarab Tail, 2000 bayld',
        fame = 'Adoulin',
        fame_level = nil,
        title = 'Inventor Extraordinaire',
        repeatable = nil,
        previous = {
            'Vegetable Vegetable Evolution',
            'Raptor Rapture',
        },
        next = {'Vegetable Vegetable Frustration'},
        requirements = nil,
        walkthrough = '1. Wait one in-game day after clearing Vegetable Vegetable Evolution.\n2. Check Amchuchu\'s Laboratory at the Inventor\'s Coalition in Western Adoulin (J-10)\n3. Trade Midrium Ingot, Urunday Lumber, and Raaz Leather to Chanteillie at the Inventor\'s Coalition. If she doesn\'t say Amchuchu is ready, wait a game day after trading the items, then return.\n4. Check Amchuchu\'s Laboratory to receive Amchuchu\'s Missive.\n5. Talk to Cid in Metalworks.\n6. Check Amchuchu\'s Laboratory for reward.\nNote: Raptor Rapture is required -- some information about that quest is mentioned in one of the cutscenes.',
        notes = nil,
    },
    ['Vegetable Vegetable Evolution'] = {
        id = 109,
        start_npc = 'Door: Amuchuchu\'s Laboratory',
        start_zone = 'Western Adoulin',
        start_pos = nil,
        description = 'Midras has headed off to Yorcia Weald for further research into potential fertilizer ingredients, and Amchuchu is worried sick about him. Venture into the forest and ensure that he is safe.',
        reward = '2,000 Bayld and 12 Rarab Tails',
        fame = 'Adoulin',
        fame_level = '4',
        title = 'Vegetable Evolutionary',
        repeatable = nil,
        previous = {'Vegetable Vegetable Revolution'},
        next = {'Vegetable Vegetable Crisis'},
        requirements = nil,
        walkthrough = '1. Wait till the next game day and zone after clearing Vegetable Vegetable Revolution.\n2. Click on the Door: Amuchuchu\'s Laboratory in the back of the Inventors\' Coalition for a cutscene.\n3. Check the ??? in Yorcia Weald at (I-8) (Near Ergon Locus "Bryophitic Boulder") for a cutscene. You will obtain the [Key Item] Midras\'s explosive sample and [Key Item] Report on Midras\'s explosive.\n   - NOT located in the field of Numbing Blossoms at I-8, which also has an Ergon Locus\n   - Head north from Frontier Station or east from Bivouac #1. Very close to I-7/8 grid lines. (Taking Bivouac #1 likely will have a Reive blocking your path.)\n   - You may encounter 2 "timed bushes" along your road; just wait until they disappear (usually after 5-10 minutes). (These bushes are now removed as part of the Summer 2025 update.)\n   - MUST have Magicite, the Rank 4 mission completed in one of the starter nations or else Midras will say that you don\'t know the Tenshodo.\n4. After that enter the Tenshodo in Lower Jeuno for a cutscene.\n5. Then head back to Inventors\' Coalition and click Door: Amuchuchu\'s Laboratory for CS and your reward.',
        notes = nil,
    },
    ['Vegetable Vegetable Frustration'] = {
        id = 111,
        start_npc = 'Amchuchu (Inventors\' Coalition',
        start_zone = 'Western Adoulin)',
        start_pos = nil,
        description = 'Hoping to lift Midras out of his melancholic state, Amchuchu has sent you to Bastok to find out what first inspired him to become an inventor.',
        reward = '2,000 Bayld',
        fame = 'Adoulin',
        fame_level = nil,
        title = 'Vegetable Hero',
        repeatable = nil,
        previous = {
            'Vegetable Vegetable Crisis',
            'The Usual',
        },
        next = nil,
        requirements = {
            {name = 'Sabiki Rig', count = 1},
        },
        walkthrough = '1. Wait one in game day after clearing Vegetable Vegetable Crisis.\n   - Finish Cid\'s Secret and The Usual Bastok quests\n2. Check Amchuchu\'s Laboratory at the Inventor\'s Coalition in Western Adoulin (J-10) for a cutscene.\n3. Head to the Metalworks in Bastok and speak with Raibaht at (G-8).\n4. Go to Palborough Mines Map 3 (G-8) and examine the Peculiar Fissure.\n   - Home point to Palborough Mines is fastest way.\n5. Bang on the rock three times and then think.\n6. Return to Raibaht.\n7. Go to the Adoulin Waterfront Waypoint in Western Adoulin and examine the Contemplation Site at (I-5).\n   - Trade it a Sabiki Rig to obtain [Key Item] Packet of Midras\'s explosives.\n8. Return to the Peculiar Fissure and examine it for a short cutscene.\n9. Examine it again to spawn Incensed Pineapple, a bomb NM.\n   - Players not advanced to this point in the quest cannot participate in the fight.  Players that have completed this quest may participate.\n   - The bomb must be defeated before it uses self-destruct. Difficult fight if not properly prepared.\n     - Dispelling its Berserk effect right away will keep it from using self-destruct. Blaze spikes is repetitively used and will interfere with dispelling and require using multiple dispels or stuns.\n     - Bomb will spam either Berserk or Blaze Spikes as soon as either is dispelled.\n     - Simplest way to approach the fight is stack dispel Trusts along with stuns. BLU\'s head-butt spam makes this fight almost trivial.\n     - Some Trusts that use Dispel include Qultada, Koru-Moru, Arciela (I or II), Ovjang, and Ajido-Marujido.\n     - Trust weaponskills that don\'t hit hard are fine. Take your time, just melee while focusing on dispels and stuns and let trusts assist you with both.\n   - If it uses self-destruct, you must reexamine the Contemplation Site then trade another Sabiki Rig to it for a new key item.\n   - When it is at 1HP it will attempt to use self-destruct and immediately die without it going off.\n10. Examine the Peculiar Fissure again for a cutscene and the two Key Items: Tarnished ring (relating to Sirius) and Rusty locket (relating to Almid).\n11. Return to Raibaht.\n12. Return to the Contemplation Site for a cutscene and your reward.',
        notes = nil,
    },
    ['Vegetable Vegetable Revolution'] = {
        id = 108,
        start_npc = 'Door: Amuchuchu\'s Laboratory',
        start_zone = 'Western Adoulin',
